import { RpcError } from "starknet"

type NumericCode = {
  readonly code: number
}

type BaseErrorShape = {
  readonly baseError: unknown
}

const hasNumericCode = (value: unknown): value is NumericCode =>
  typeof value === "object" &&
  value !== null &&
  "code" in value &&
  typeof value.code === "number"

const hasBaseError = (value: unknown): value is BaseErrorShape =>
  typeof value === "object" &&
  value !== null &&
  "baseError" in value

export const extractRpcErrorCode = (error: unknown): number => {
  if (error instanceof RpcError) {
    return error.code
  }

  if (hasNumericCode(error)) {
    return error.code
  }

  if (hasBaseError(error) && hasNumericCode(error.baseError)) {
    return error.baseError.code
  }

  return -1
}
