import { Config, Effect, Schema } from "effect"
import { Account, CallData, RpcProvider, hash, stark } from "starknet"
import {
  AccountDeployError,
  InsufficientFundsError,
  StarknetRpcError,
} from "./errors"
import { ContractAddress, TxHash } from "./types"
import type { DeployPrecompute, PackedPublicKey } from "./types"
import { extractRpcErrorCode } from "./starknet-utils"

const STRK_TOKEN_ADDRESS =
  "REDACTED"

export class StarknetService extends Effect.Service<StarknetService>()(
  "StarknetService",
  {
    accessors: true,
    effect: Effect.gen(function* () {
      const rpcUrl = yield* Config.string("NEXT_PUBLIC_STARKNET_RPC_URL")
      const classHash = yield* Config.string("FALCON_ACCOUNT_CLASS_HASH")
      const provider = new RpcProvider({ nodeUrl: rpcUrl })

      const computeDeployAddress = Effect.fn("StarknetService.computeDeployAddress")(
        function* (packedPk: PackedPublicKey) {
          const precompute = yield* Effect.try({
            try: () => {
              const constructorCalldata = CallData.compile({
                pk_packed: packedPk.slots,
              })
              const salt = stark.randomAddress()
              const address = hash.calculateContractAddressFromHash(
                salt,
                classHash,
                constructorCalldata,
                0,
              )
              return {
                address,
                salt,
                constructorCalldata: [...constructorCalldata],
              }
            },
            catch: (error) =>
              new StarknetRpcError({
                message: String(error),
                code: extractRpcErrorCode(error),
              }),
          })

          const address = yield* Effect.try({
            try: () => Schema.decodeSync(ContractAddress)(precompute.address),
            catch: (error) =>
              new StarknetRpcError({
                message: `Invalid contract address: ${String(error)}`,
                code: -1,
              }),
          })

          return {
            address,
            salt: precompute.salt,
            constructorCalldata: precompute.constructorCalldata,
          } satisfies DeployPrecompute
        },
      )

      const getBalance = Effect.fn("StarknetService.getBalance")(
        function* (address: string) {
          return yield* Effect.tryPromise({
            try: async () => {
              const result = await provider.callContract({
                contractAddress: STRK_TOKEN_ADDRESS,
                entrypoint: "balanceOf",
                calldata: [address],
              })
              return BigInt(result[0])
            },
            catch: (error) =>
              new StarknetRpcError({
                message: String(error),
                code: extractRpcErrorCode(error),
              }),
          })
        },
      )

      const deployAccount = Effect.fn("StarknetService.deployAccount")(
        function* (precompute: DeployPrecompute, privateKey: string) {
          const balance = yield* getBalance(precompute.address)

          if (balance === 0n) {
            yield* Effect.fail(
              new InsufficientFundsError({
                message: "Account balance is 0 — fund the account before deploying",
                address: precompute.address,
                required: ">0",
              }),
            )
          }

          // starknet v9 Account constructor takes a single AccountOptions object
          const account = new Account({
            provider,
            address: precompute.address,
            signer: privateKey,
          })

          const result = yield* Effect.tryPromise({
            try: () =>
              account.deployAccount({
                classHash,
                constructorCalldata: precompute.constructorCalldata,
                addressSalt: precompute.salt,
                contractAddress: precompute.address,
              }),
            catch: (error) =>
              new AccountDeployError({ message: String(error) }),
          })

          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(result.transaction_hash),
            catch: (error) =>
              new AccountDeployError({
                message: `Tx failed: ${error}`,
                txHash: result.transaction_hash,
              }),
          })

          const txHash = yield* Effect.try({
            try: () => Schema.decodeSync(TxHash)(result.transaction_hash),
            catch: (error) =>
              new AccountDeployError({
                message: `Invalid transaction hash: ${String(error)}`,
                txHash: result.transaction_hash,
              }),
          })

          const address = yield* Effect.try({
            try: () => Schema.decodeSync(ContractAddress)(result.contract_address),
            catch: (error) =>
              new AccountDeployError({
                message: `Invalid contract address: ${String(error)}`,
                txHash: result.transaction_hash,
              }),
          })

          return {
            txHash,
            address,
          }
        },
      )

      const waitForTx = Effect.fn("StarknetService.waitForTx")(
        function* (txHash: string) {
          yield* Effect.tryPromise({
            try: () => provider.waitForTransaction(txHash),
            catch: (error) =>
              new StarknetRpcError({
                message: String(error),
                code: extractRpcErrorCode(error),
              }),
          })
        },
      )

      return {
        computeDeployAddress,
        getBalance,
        deployAccount,
        waitForTx,
      }
    }),
  },
) {}
