import { describe, expect, it } from "bun:test"
import { ConfigProvider, Effect, Exit, Layer, Schema } from "effect"

import { StarknetService } from "../../services/StarknetService"
import {
  AccountDeployError,
  InsufficientFundsError,
  StarknetRpcError,
} from "../../services/errors"
import { ContractAddress, TxHash } from "../../services/types"
import type { DeployPrecompute, PackedPublicKey } from "../../services/types"

const mockPrecompute: DeployPrecompute = {
  address: Schema.decodeSync(ContractAddress)(
    "0x049d36570d4e46f48e99674bd3fcc84644ddd6b96f7c741b1562b82f9e004dc7",
  ),
  salt: "0xabc123",
  constructorCalldata: ["0x1", "0x2", "0x3"],
}

const mockTxHash = Schema.decodeSync(TxHash)("0x7f3e2a1b9c4d5e6f")

const mockPk: PackedPublicKey = {
  slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
}

const makeSuccessService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(mockPrecompute),
    getBalance: (_addr: string) => Effect.succeed(BigInt("1000000000000000000")),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.succeed({ txHash: mockTxHash, address: mockPrecompute.address }),
    waitForTx: (_tx: string) => Effect.void,
  })

const makeFailingService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.fail(new StarknetRpcError({ message: "mock rpc error", code: -32000 })),
    getBalance: (_addr: string) =>
      Effect.fail(new StarknetRpcError({ message: "balance fetch failed", code: -32000 })),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "deploy rejected" })),
    waitForTx: (_tx: string) =>
      Effect.fail(new StarknetRpcError({ message: "tx timeout", code: -32003 })),
  })

const makeInsufficientFundsService = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(mockPrecompute),
    getBalance: (_addr: string) => Effect.succeed(0n),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.fail(
        new InsufficientFundsError({
          message: "Account balance is 0 — fund the account before deploying",
          address: mockPrecompute.address,
          required: ">0",
        }),
      ),
    waitForTx: (_tx: string) => Effect.void,
  })

const runWith = <A, E>(
  effect: Effect.Effect<A, E, StarknetService>,
  serviceLayer: Layer.Layer<StarknetService>,
): Promise<Exit.Exit<A, E>> => Effect.runPromiseExit(effect.pipe(Effect.provide(serviceLayer)))

describe("StarknetService.computeDeployAddress (mocked)", () => {
  it("succeeds and returns DeployPrecompute", async () => {
    const exit = await runWith(StarknetService.computeDeployAddress(mockPk), makeSuccessService())

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.address.startsWith("0x")).toBe(true)
      expect(exit.value.salt.startsWith("0x")).toBe(true)
      expect(exit.value.constructorCalldata.length).toBeGreaterThan(0)
    }
  })

  it("fails with StarknetRpcError when service fails", async () => {
    const exit = await runWith(StarknetService.computeDeployAddress(mockPk), makeFailingService())

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

describe("StarknetService.getBalance (mocked)", () => {
  it("succeeds and returns a bigint", async () => {
    const exit = await runWith(StarknetService.getBalance("0x1234"), makeSuccessService())

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(BigInt("1000000000000000000"))
    }
  })

  it("fails with StarknetRpcError when RPC call fails", async () => {
    const exit = await runWith(StarknetService.getBalance("0xdeadbeef"), makeFailingService())

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

describe("StarknetService.deployAccount (mocked)", () => {
  it("succeeds and returns txHash and address", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPrecompute, "0xprivkey"),
      makeSuccessService(),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.txHash).toBe(mockTxHash)
      expect(exit.value.address).toBe(mockPrecompute.address)
    }
  })

  it("fails with AccountDeployError when deployment is rejected", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPrecompute, "0xprivkey"),
      makeFailingService(),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
    }
  })
})

describe("StarknetService.deployAccount — balance gate (mocked)", () => {
  it("fails with InsufficientFundsError when balance is 0", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(mockPrecompute, "0xprivkey"),
      makeInsufficientFundsService(),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("InsufficientFundsError")
    }
  })
})

describe("StarknetService.waitForTx (mocked)", () => {
  it("succeeds (returns void) when transaction confirms", async () => {
    const exit = await runWith(StarknetService.waitForTx("0xabc123"), makeSuccessService())

    expect(Exit.isSuccess(exit)).toBe(true)
  })

  it("fails with StarknetRpcError when tx times out", async () => {
    const exit = await runWith(StarknetService.waitForTx("0xdeadbeef"), makeFailingService())

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

describe("StarknetService.computeDeployAddress (real implementation)", () => {
  const withTestConfig = ConfigProvider.fromMap(
    new Map([
      ["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"],
      ["FALCON_ACCOUNT_CLASS_HASH", "0x0"],
    ]),
  )

  it("returns DeployPrecompute with address, salt, and constructorCalldata", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(withTestConfig)),
      ),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      const precompute = exit.value
      expect(precompute.address.startsWith("0x")).toBe(true)
      expect(precompute.salt.startsWith("0x")).toBe(true)
      expect(precompute.constructorCalldata.length).toBeGreaterThan(0)
    }
  })

  it("two calls with same input produce different salts", async () => {
    const run = () =>
      Effect.runPromiseExit(
        StarknetService.computeDeployAddress(mockPk).pipe(
          Effect.provide(StarknetService.Default),
          Effect.provide(Layer.setConfigProvider(withTestConfig)),
        ),
      )

    const exit1 = await run()
    const exit2 = await run()

    expect(Exit.isSuccess(exit1)).toBe(true)
    expect(Exit.isSuccess(exit2)).toBe(true)

    if (Exit.isSuccess(exit1) && Exit.isSuccess(exit2)) {
      expect(exit1.value.salt).not.toBe(exit2.value.salt)
      expect(exit1.value.address).not.toBe(exit2.value.address)
    }
  })

  it("fails when FALCON_ACCOUNT_CLASS_HASH is missing", async () => {
    const partialConfig = ConfigProvider.fromMap(
      new Map([["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"]]),
    )

    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(partialConfig)),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
  })
})

describe("StarknetService initialization", () => {
  it("fails when NEXT_PUBLIC_STARKNET_RPC_URL is missing", async () => {
    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(mockPk).pipe(
        Effect.provide(StarknetService.Default),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
  })
})
