const makeDeployOrchestrationEffect = (registry: ReturnType<typeof Registry.make>) =>
  Effect.gen(function* () {
    registry.set(deployStepAtom, { step: "generating-keypair" })
    registry.set(deployStepAtom, { step: "packing" })

    registry.set(deployStepAtom, { step: "computing-address" })
    const precompute = yield* StarknetService.computeDeployAddress(MOCK_PACKED_PK)

    registry.set(deployStepAtom, { step: "awaiting-funds", address: precompute.address })
    const balance = yield* StarknetService.getBalance(precompute.address)

    if (balance === 0n) {
      yield* Effect.fail(
        new InsufficientFundsError({
          message: "Account not funded — send STRK to deploy",
          address: precompute.address,
          required: "1000000000000000000",
        }),
      )
    }

    registry.set(deployStepAtom, { step: "deploying", address: precompute.address })
    const result = yield* StarknetService.deployAccount(precompute, MOCK_PRIVATE_KEY)

    registry.set(deployStepAtom, {
      step: "deployed",
      address: result.address,
      txHash: result.txHash,
    })

    return { address: result.address, txHash: result.txHash, balance }
  })

describe("Orchestrated 5-step deploy flow", () => {
  it("happy path: sequence reaches deployed", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeSuccessLayer()),
      ),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.address).toBe(MOCK_ADDRESS)
      expect(exit.value.txHash).toBe(MOCK_TX_HASH)
      expect(exit.value.balance).toBe(FUNDED_BALANCE)

      registry.set(deployedAddressAtom, Option.some(exit.value.address))
      registry.set(deployTxHashAtom, Option.some(exit.value.txHash))
      expect(getSome(registry.get(deployedAddressAtom))).toBe(MOCK_ADDRESS)
      expect(getSome(registry.get(deployTxHashAtom))).toBe(MOCK_TX_HASH)
    }

    expect(steps).toEqual([
      "generating-keypair",
      "packing",
      "computing-address",
      "awaiting-funds",
      "deploying",
      "deployed",
    ])
  })

  it("RPC failure at computeDeployAddress stops flow before awaiting-funds", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeRpcFailureLayer()),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }

    expect(steps).toEqual(["generating-keypair", "packing", "computing-address"])
  })

  it("deploy rejection fails after deploying step", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeDeployFailureLayer()),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
    }

    expect(steps).toEqual([
      "generating-keypair",
      "packing",
      "computing-address",
      "awaiting-funds",
      "deploying",
    ])
  })

  it("zero balance fails with InsufficientFundsError before deploying", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeZeroBalanceLayer()),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("InsufficientFundsError")
    }

    expect(steps).toEqual([
      "generating-keypair",
      "packing",
      "computing-address",
      "awaiting-funds",
    ])
  })

  it("registry isolation: two deploy registries do not share state", () => {
    const registry1 = Registry.make()
    const registry2 = Registry.make()

    registry1.set(deployStepAtom, { step: "deploying", address: "0x1111" })
    registry2.set(deployStepAtom, { step: "computing-address" })

    expect(registry1.get(deployStepAtom).step).toBe("deploying")
    expect(registry2.get(deployStepAtom).step).toBe("computing-address")
  })
})

