import { describe, expect, it } from "bun:test"
import { ConfigProvider, Effect, Exit, Layer, Option, Schema } from "effect"
import { Registry } from "@effect-atom/atom"

import { StarknetService } from "../../services/StarknetService"
import {
  AccountDeployError,
  InsufficientFundsError,
  StarknetRpcError,
} from "../../services/errors"
import { ContractAddress, TxHash } from "../../services/types"
import type {
  DeployPrecompute,
  PackedPublicKey,
  TxHash as TxHashType,
  ContractAddress as ContractAddressType,
} from "../../services/types"
import type { DeployStep } from "../../atoms/starknet"
import {
  deployStepAtom,
  deployedAddressAtom,
  deployTxHashAtom,
} from "../../atoms/starknet"

const MOCK_ADDRESS = Schema.decodeSync(ContractAddress)(
  "0x049d36570d4e46f48e99674bd3fcc84644ddd6b96f7c741b1562b82f9e004dc7",
)
const MOCK_TX_HASH = Schema.decodeSync(TxHash)(
  "0x7f3e2a1b9c4d5e6f0a1b2c3d4e5f6a7b",
)
const MOCK_PACKED_PK: PackedPublicKey = {
  slots: Array.from({ length: 29 }, (_, i) => `0x${i.toString(16).padStart(64, "0")}`),
}
const MOCK_PRECOMPUTE: DeployPrecompute = {
  address: MOCK_ADDRESS,
  salt: "0xdeadbeef",
  constructorCalldata: ["0x1", "0x2", "0x3"],
}
const MOCK_PRIVATE_KEY = "0xdeadbeefcafebabe1234567890abcdef"
const FUNDED_BALANCE = 1_000_000_000_000_000_000n
const ZERO_BALANCE = 0n

const makeSuccessLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(MOCK_PRECOMPUTE),
    getBalance: (_addr: string) => Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.succeed({ txHash: MOCK_TX_HASH, address: MOCK_ADDRESS }),
    waitForTx: (_tx: string) => Effect.void,
  })

const makeZeroBalanceLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(MOCK_PRECOMPUTE),
    getBalance: (_addr: string) => Effect.succeed(ZERO_BALANCE),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "should not be reached" })),
    waitForTx: (_tx: string) => Effect.void,
  })

const makeDeployFailureLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(MOCK_PRECOMPUTE),
    getBalance: (_addr: string) => Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "insufficient fee" })),
    waitForTx: (_tx: string) => Effect.void,
  })

const makeDeployRevertedLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(MOCK_PRECOMPUTE),
    getBalance: (_addr: string) => Effect.succeed(FUNDED_BALANCE),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.fail(
        new AccountDeployError({
          message: "transaction reverted",
          txHash: MOCK_TX_HASH,
        }),
      ),
    waitForTx: (_tx: string) => Effect.void,
  })

const makeRpcFailureLayer = (): Layer.Layer<StarknetService> =>
  Layer.succeed(StarknetService, {
    _tag: "StarknetService",
    computeDeployAddress: (_pk: PackedPublicKey) =>
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -32000 })),
    getBalance: (_addr: string) =>
      Effect.fail(new StarknetRpcError({ message: "connection refused", code: -32000 })),
    deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
      Effect.fail(new AccountDeployError({ message: "connection refused" })),
    waitForTx: (_tx: string) =>
      Effect.fail(new StarknetRpcError({ message: "timeout", code: -32003 })),
  })

const runWith = <A, E>(
  effect: Effect.Effect<A, E, StarknetService>,
  serviceLayer: Layer.Layer<StarknetService>,
): Promise<Exit.Exit<A, E>> => Effect.runPromiseExit(effect.pipe(Effect.provide(serviceLayer)))

const getSome = <A>(value: Option.Option<A>): A | null =>
  Option.match(value, {
    onNone: () => null,
    onSome: (inner) => inner,
  })

describe("DeployStep state machine — account-deploy scenarios", () => {
  it("idle → awaiting-funds preserves address in step payload", () => {
    const registry = Registry.make()
    registry.set(deployStepAtom, { step: "awaiting-funds", address: MOCK_ADDRESS })

    const state = registry.get(deployStepAtom)
    expect(state.step).toBe("awaiting-funds")
    if (state.step === "awaiting-funds") {
      expect(state.address).toBe(MOCK_ADDRESS)
    }
  })

  it("deployed step carries both address and txHash", () => {
    const registry = Registry.make()
    registry.set(deployStepAtom, {
      step: "deployed",
      address: MOCK_ADDRESS,
      txHash: MOCK_TX_HASH,
    })

    const state = registry.get(deployStepAtom)
    expect(state.step).toBe("deployed")
    if (state.step === "deployed") {
      expect(state.address).toBe(MOCK_ADDRESS)
      expect(state.txHash).toBe(MOCK_TX_HASH)
    }
  })

  it("deployedAddressAtom and deployTxHashAtom store Option values", () => {
    const registry = Registry.make()
    registry.set(deployedAddressAtom, Option.some(MOCK_ADDRESS))
    registry.set(deployTxHashAtom, Option.some(MOCK_TX_HASH))

    expect(getSome(registry.get(deployedAddressAtom))).toBe(MOCK_ADDRESS)
    expect(getSome(registry.get(deployTxHashAtom))).toBe(MOCK_TX_HASH)
  })

  it("error resets Option atoms to none", () => {
    const registry = Registry.make()
    registry.set(deployedAddressAtom, Option.none())
    registry.set(deployTxHashAtom, Option.none())
    registry.set(deployStepAtom, { step: "error", message: "retry" })

    expect(Option.isNone(registry.get(deployedAddressAtom))).toBe(true)
    expect(Option.isNone(registry.get(deployTxHashAtom))).toBe(true)
  })

  it("subscribe fires on each deploy step transition", () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    registry.set(deployStepAtom, { step: "generating-keypair" })
    registry.set(deployStepAtom, { step: "packing" })
    registry.set(deployStepAtom, { step: "computing-address" })

    expect(steps).toEqual(["generating-keypair", "packing", "computing-address"])
  })
})

describe("StarknetService.computeDeployAddress — account-deploy step 3", () => {
  it("success: returns DeployPrecompute payload", async () => {
    const exit = await runWith(
      StarknetService.computeDeployAddress(MOCK_PACKED_PK),
      makeSuccessLayer(),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.address).toBe(MOCK_ADDRESS)
      expect(exit.value.salt).toBe("0xdeadbeef")
      expect(exit.value.constructorCalldata.length).toBe(3)
    }
  })

  it("failure: StarknetRpcError propagates", async () => {
    const exit = await runWith(
      StarknetService.computeDeployAddress(MOCK_PACKED_PK),
      makeRpcFailureLayer(),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })

  it("real implementation returns DeployPrecompute and needs class hash config", async () => {
    const withConfig = ConfigProvider.fromMap(
      new Map([
        ["NEXT_PUBLIC_STARKNET_RPC_URL", "http://localhost:9999"],
        ["FALCON_ACCOUNT_CLASS_HASH", "0x0"],
      ]),
    )

    const exit = await Effect.runPromiseExit(
      StarknetService.computeDeployAddress(MOCK_PACKED_PK).pipe(
        Effect.provide(StarknetService.Default),
        Effect.provide(Layer.setConfigProvider(withConfig)),
      ),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.address.startsWith("0x")).toBe(true)
      expect(exit.value.salt.startsWith("0x")).toBe(true)
    }
  })
})

describe("StarknetService.getBalance — awaiting-funds gate", () => {
  it("returns funded balance", async () => {
    const exit = await runWith(StarknetService.getBalance(MOCK_ADDRESS), makeSuccessLayer())

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(FUNDED_BALANCE)
    }
  })

  it("returns zero balance", async () => {
    const exit = await runWith(StarknetService.getBalance(MOCK_ADDRESS), makeZeroBalanceLayer())

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value).toBe(ZERO_BALANCE)
    }
  })

  it("failure: StarknetRpcError from RPC", async () => {
    const exit = await runWith(StarknetService.getBalance(MOCK_ADDRESS), makeRpcFailureLayer())

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

describe("StarknetService.deployAccount — step 5", () => {
  it("success: returns txHash and address", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(MOCK_PRECOMPUTE, MOCK_PRIVATE_KEY),
      makeSuccessLayer(),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.txHash).toBe(MOCK_TX_HASH)
      expect(exit.value.address).toBe(MOCK_ADDRESS)
    }
  })

  it("failure: AccountDeployError without txHash", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(MOCK_PRECOMPUTE, MOCK_PRIVATE_KEY),
      makeDeployFailureLayer(),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
      expect(JSON.stringify(exit.cause)).toContain("insufficient fee")
    }
  })

  it("failure: AccountDeployError with txHash", async () => {
    const exit = await runWith(
      StarknetService.deployAccount(MOCK_PRECOMPUTE, MOCK_PRIVATE_KEY),
      makeDeployRevertedLayer(),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
      expect(JSON.stringify(exit.cause)).toContain(MOCK_TX_HASH)
    }
  })

  it("insufficient funds maps to InsufficientFundsError", async () => {
    const insufficientFundsLayer = Layer.succeed(StarknetService, {
      _tag: "StarknetService",
      computeDeployAddress: (_pk: PackedPublicKey) => Effect.succeed(MOCK_PRECOMPUTE),
      getBalance: (_addr: string) => Effect.succeed(ZERO_BALANCE),
      deployAccount: (_precompute: DeployPrecompute, _sk: string) =>
        Effect.fail(
          new InsufficientFundsError({
            message: "Account not funded — send STRK to deploy",
            address: MOCK_ADDRESS,
            required: "1000000000000000000",
          }),
        ),
      waitForTx: (_tx: string) => Effect.void,
    })

    const exit = await runWith(
      StarknetService.deployAccount(MOCK_PRECOMPUTE, MOCK_PRIVATE_KEY),
      insufficientFundsLayer,
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("InsufficientFundsError")
    }
  })
})

describe("StarknetService.waitForTx — post-deploy confirmation", () => {
  it("success: resolves when tx confirms", async () => {
    const exit = await runWith(StarknetService.waitForTx(MOCK_TX_HASH), makeSuccessLayer())

    expect(Exit.isSuccess(exit)).toBe(true)
  })

  it("failure: StarknetRpcError on timeout", async () => {
    const exit = await runWith(StarknetService.waitForTx(MOCK_TX_HASH), makeRpcFailureLayer())

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }
  })
})

const makeDeployOrchestrationEffect = (registry: ReturnType<typeof Registry.make>) =>
  Effect.gen(function* () {
    registry.set(deployStepAtom, { step: "generating-keypair" })
    registry.set(deployStepAtom, { step: "packing" })

    registry.set(deployStepAtom, { step: "computing-address" })
    const precompute = yield* StarknetService.computeDeployAddress(MOCK_PACKED_PK)

    registry.set(deployStepAtom, { step: "awaiting-funds", address: precompute.address })
    const balance = yield* StarknetService.getBalance(precompute.address)

    if (balance === 0n) {
      yield* Effect.fail(
        new InsufficientFundsError({
          message: "Account not funded — send STRK to deploy",
          address: precompute.address,
          required: "1000000000000000000",
        }),
      )
    }

    registry.set(deployStepAtom, { step: "deploying", address: precompute.address })
    const result = yield* StarknetService.deployAccount(precompute, MOCK_PRIVATE_KEY)

    registry.set(deployStepAtom, {
      step: "deployed",
      address: result.address,
      txHash: result.txHash,
    })

    return { address: result.address, txHash: result.txHash, balance }
  })

describe("Orchestrated 5-step deploy flow", () => {
  it("happy path: sequence reaches deployed", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeSuccessLayer()),
      ),
    )

    expect(Exit.isSuccess(exit)).toBe(true)
    if (Exit.isSuccess(exit)) {
      expect(exit.value.address).toBe(MOCK_ADDRESS)
      expect(exit.value.txHash).toBe(MOCK_TX_HASH)
      expect(exit.value.balance).toBe(FUNDED_BALANCE)

      registry.set(deployedAddressAtom, Option.some(exit.value.address))
      registry.set(deployTxHashAtom, Option.some(exit.value.txHash))
      expect(getSome(registry.get(deployedAddressAtom))).toBe(MOCK_ADDRESS)
      expect(getSome(registry.get(deployTxHashAtom))).toBe(MOCK_TX_HASH)
    }

    expect(steps).toEqual([
      "generating-keypair",
      "packing",
      "computing-address",
      "awaiting-funds",
      "deploying",
      "deployed",
    ])
  })

  it("RPC failure at computeDeployAddress stops flow before awaiting-funds", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeRpcFailureLayer()),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("StarknetRpcError")
    }

    expect(steps).toEqual(["generating-keypair", "packing", "computing-address"])
  })

  it("deploy rejection fails after deploying step", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeDeployFailureLayer()),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
      expect(JSON.stringify(exit.cause)).toContain("AccountDeployError")
    }

    expect(steps).toEqual([
      "generating-keypair",
      "packing",
      "computing-address",
      "awaiting-funds",
      "deploying",
    ])
  })

  it("zero balance fails with InsufficientFundsError before deploying", async () => {
    const registry = Registry.make()
    const steps: string[] = []

    registry.subscribe(deployStepAtom, (value) => {
      steps.push(value.step)
    })

    const exit = await Effect.runPromiseExit(
      makeDeployOrchestrationEffect(registry).pipe(
        Effect.provide(makeZeroBalanceLayer()),
      ),
    )

    expect(Exit.isFailure(exit)).toBe(true)
    if (Exit.isFailure(exit)) {
